import React, { useEffect, useMemo, useState } from "react";
import { NavLink, useNavigate } from "react-router-dom";
import {
  cancelAccident,
  getAdminAccidents,
  getAdminDispatchLogs,
  getAdminOverview,
  manualDispatch,
  sendDetectionEvent,
} from "../../service/apiservice";
import { connectSocket, disconnectSocket } from "../../service/socketService";
import { clearAuth, getStoredUser } from "../../utils/auth";
import "./AdminDashboard.css";

const AdminDashboard = () => {
  const user = useMemo(() => getStoredUser(), []);
  const navigate = useNavigate();

  const [overview, setOverview] = useState(null);
  const [accidents, setAccidents] = useState([]);
  const [logs, setLogs] = useState([]);
  const [detector, setDetector] = useState({ latitude: "12.9716", longitude: "77.5946", severity: "High", confidenceScore: "0.93" });
  const [error, setError] = useState("");

  const load = async () => {
    try {
      const [ov, ac, dl] = await Promise.all([getAdminOverview(), getAdminAccidents(), getAdminDispatchLogs()]);
      setOverview(ov.overview);
      setAccidents(ac.accidents || []);
      setLogs(dl.logs || []);
    } catch (err) {
      setError(err.message || "Failed to load admin data");
    }
  };

  useEffect(() => {
    load();
    const socket = connectSocket();
    socket.on("accident:new", load);
    socket.on("dispatch:updated", load);
    socket.on("dispatch:pending", load);
    socket.on("response:received", load);

    return () => {
      socket.off("accident:new");
      socket.off("dispatch:updated");
      socket.off("dispatch:pending");
      socket.off("response:received");
      disconnectSocket();
    };
  }, []);

  const logout = () => {
    clearAuth();
    navigate("/login");
  };

  const onCancel = async (accidentId) => {
    await cancelAccident(accidentId);
    load();
  };

  const onManualDispatch = async (accidentId) => {
    await manualDispatch(accidentId, "Manual dispatch by admin");
    load();
  };

  const simulateDetection = async (e) => {
    e.preventDefault();
    setError("");
    try {
      await sendDetectionEvent({
        latitude: Number(detector.latitude),
        longitude: Number(detector.longitude),
        severity: detector.severity,
        confidenceScore: Number(detector.confidenceScore),
      });
      load();
    } catch (err) {
      setError(err.message || "Could not create detection event");
    }
  };

  return (
    <div className="admin-page">
      <aside className="sidebar">
        <h2>Control Panel</h2>
        <NavLink to="/admin">Overview</NavLink>
        <NavLink to="/admin/users">Users</NavLink>
        {user?.role === "super_admin" && <NavLink to="/super-admin">System Config</NavLink>}
      </aside>

      <main className="content">
        <header className="topbar">
          <div>
            <h1>Accident Response Admin</h1>
            <p>{user?.role}</p>
          </div>
          <button onClick={logout}>Logout</button>
        </header>

        {error && <p className="error-text">{error}</p>}

        {overview && (
          <section className="stats-grid">
            <div className="stat-card"><h3>Users</h3><p>{overview.users}</p></div>
            <div className="stat-card"><h3>Accidents</h3><p>{overview.accidents}</p></div>
            <div className="stat-card"><h3>Pending Accidents</h3><p>{overview.pendingAccidents}</p></div>
            <div className="stat-card"><h3>Active Dispatches</h3><p>{overview.activeDispatches}</p></div>
            <div className="stat-card"><h3>No Responses</h3><p>{overview.unresolvedResponses}</p></div>
          </section>
        )}

        <section className="panel">
          <h3>External Detector Event (Simulation)</h3>
          <form className="detector-form" onSubmit={simulateDetection}>
            <input value={detector.latitude} onChange={(e) => setDetector({ ...detector, latitude: e.target.value })} placeholder="Latitude" />
            <input value={detector.longitude} onChange={(e) => setDetector({ ...detector, longitude: e.target.value })} placeholder="Longitude" />
            <select value={detector.severity} onChange={(e) => setDetector({ ...detector, severity: e.target.value })}>
              <option>Low</option>
              <option>Medium</option>
              <option>High</option>
              <option>Critical</option>
            </select>
            <input value={detector.confidenceScore} onChange={(e) => setDetector({ ...detector, confidenceScore: e.target.value })} placeholder="Confidence 0-1" />
            <button type="submit">Create Accident Event</button>
          </form>
        </section>

        <section className="panel">
          <h3>Accident Records</h3>
          <table>
            <thead>
              <tr>
                <th>Time</th>
                <th>Severity</th>
                <th>Status</th>
                <th>Location</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {accidents.map((acc) => (
                <tr key={acc._id}>
                  <td>{new Date(acc.createdAt).toLocaleString()}</td>
                  <td>{acc.severity}</td>
                  <td>{acc.status}</td>
                  <td>{acc.location?.coordinates?.[1]}, {acc.location?.coordinates?.[0]}</td>
                  <td>
                    <button onClick={() => onManualDispatch(acc._id)}>Dispatch</button>
                    {acc.status !== "Cancelled" && <button onClick={() => onCancel(acc._id)}>Cancel</button>}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </section>

        <section className="panel">
          <h3>Dispatch Logs</h3>
          <table>
            <thead>
              <tr>
                <th>Assigned</th>
                <th>Status</th>
                <th>Reason</th>
              </tr>
            </thead>
            <tbody>
              {logs.map((log) => (
                <tr key={log._id}>
                  <td>{new Date(log.assignedTime).toLocaleString()}</td>
                  <td>{log.status}</td>
                  <td>{log.reason}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </section>
      </main>
    </div>
  );
};

export default AdminDashboard;
